// ============================================================
// MAPEADOR UNIVERSAL DE GOOGLE FORMS
// Google Forms puede enviar datos de muchas formas según
// cómo se configure el Apps Script de envío. Este nodo
// maneja los formatos más comunes.
// ============================================================
const crypto = require('crypto');
const raw = $input.first().json;
const plataforma = $vars.PLATAFORMA_NOMBRE || 'Demo';

// --- Detectar formato de payload ---
// Formato A: Apps Script envía { responses: { 'Pregunta': 'Respuesta', ... } }
// Formato B: Apps Script envía campos planos directamente
// Formato C: Google Forms Zapier-style con 'entry.XXXXX' keys
const data = raw.responses || raw.entry || raw;

const norm = (str) =>
  String(str)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();

const findVal = (obj, claves) => {
  for (const clave of claves) {
    const key = Object.keys(obj).find(k => norm(k).includes(clave));
    if (key && obj[key] !== undefined && String(obj[key]).trim() !== '') {
      return String(obj[key]).trim();
    }
  }
  return null;
};

// Texto de la reseña
const texto = findVal(data, [
  'comentario', 'resena', 'texto', 'opinion', 'feedback',
  'descripcion', 'mensaje', 'experiencia', 'review', 'content'
]);

if (!texto || texto.length < 5) {
  throw new Error('[VOC Forms] Payload sin campo de texto identificable: ' + JSON.stringify(Object.keys(data)));
}

// Calificación / estrellas
const calRaw = findVal(data, [
  'calificacion', 'rating', 'estrellas', 'puntuacion', 'stars', 'nota', 'score'
]);
const calificacion = calRaw ? (parseFloat(calRaw) || '') : '';

// Autor / nombre del cliente
const autor = findVal(data, [
  'nombre', 'name', 'autor', 'paciente', 'cliente', 'huesped', 'usuario'
]) || 'Anónimo';

// Servicio / área específica (info extra que no tienen Google Maps)
const servicio = findVal(data, [
  'servicio', 'area', 'departamento', 'especialidad', 'producto', 'sede'
]) || '';

// Email del autor (para alerta de seguimiento si es queja)
const emailAutor = findVal(data, ['email', 'correo', 'mail']) || '';

// Fecha de envío del form
const fechaResena = new Date().toISOString().split('T')[0];

// Hash de deduplicación
const textoParaHash = texto.toLowerCase().replace(/\s+/g, ' ');
const idHash = crypto
  .createHash('md5')
  .update(textoParaHash)
  .digest('hex')
  .substring(0, 16);

return [{
  json: {
    id:                   idHash,
    texto_original:       texto,
    idioma:               'pendiente_deteccion',
    fuente:               'google_forms',
    plataforma:           plataforma,
    fecha_resena:         fechaResena,
    fecha_ingesta:        fechaResena,
    calificacion_estrella: calificacion,
    autor:                autor,
    url_origen:           '',
    estado_procesado:     'pendiente',
    // Campos extra del form (útiles para enrutamiento de alertas)
    _servicio_form:       servicio,
    _email_autor:         emailAutor,
    // Campos IA vacíos
    sentimiento:          '',
    categoria:            '',
    score_urgencia:       '',
    entidades_clave:      '',
    resumen_ia:           '',
    accion_sugerida:      ''
  }
}];

