function onFormSubmit(e) {
  const responses = {};
  e.response.getItemResponses().forEach(r => {
    responses[r.getItem().getTitle()] = r.getResponse();
  });
  const payload = JSON.stringify({ responses: responses, form_id: e.source.getId() });
  UrlFetchApp.fetch('https://TU_N8N_HOST/webhook/voc-forms-intake', {
    method: 'post',
    contentType: 'application/json',
    payload: payload
  });
}
// Trigger: Editar → Activadores → onFormSubmit → Al enviar formulario
